INSERT INTO words (word, category_id, position, tag, zh, en, example_en, example_zh, synonyms) VALUES
  ('so', 'op', 91, 'OP', '如此；所以；这样', 'in this way, to that degree, or therefore', 'The basket was heavy, so I put it down.', '篮子很重，所以我把它放下。', '[{"w":"quite","def":"quite: 相关的动作或关系词","vs":"与 so 相比，用于和主词比较动作方向、许可或连接关系","use":"造句、改写、基础语法替换，例如 \"quite\" / \"so\" 的替换练习"},{"w":"very","def":"very: 可帮助扩展句型的基础词","vs":"与 so 相比，比主词更偏向另一个动作阶段或语气","use":"短句练习、问答转换，例如 \"very\" / \"so\" 的替换练习"},{"w":"tomorrow","def":"tomorrow: 同一组 Basic English 操作词","vs":"与 so 相比，保留基础含义，但句中功能不同","use":"动词、介词、连词的搭配训练，例如 \"tomorrow\" / \"so\" 的替换练习"}]'),
  ('very', 'op', 92, 'OP', '非常；很', 'to a high degree', 'This is a very clear example.', '这是一个非常清楚的例子。', '[{"w":"so","def":"so: 相关的动作或关系词","vs":"与 very 相比，用于和主词比较动作方向、许可或连接关系","use":"造句、改写、基础语法替换，例如 \"so\" / \"very\" 的替换练习"},{"w":"tomorrow","def":"tomorrow: 可帮助扩展句型的基础词","vs":"与 very 相比，比主词更偏向另一个动作阶段或语气","use":"短句练习、问答转换，例如 \"tomorrow\" / \"very\" 的替换练习"},{"w":"yesterday","def":"yesterday: 同一组 Basic English 操作词","vs":"与 very 相比，保留基础含义，但句中功能不同","use":"动词、介词、连词的搭配训练，例如 \"yesterday\" / \"very\" 的替换练习"}]'),
  ('tomorrow', 'op', 93, 'OP', '明天', 'the day after today', 'We will go to the market tomorrow.', '我们明天会去市场。', '[{"w":"very","def":"very: 相关的动作或关系词","vs":"与 tomorrow 相比，用于和主词比较动作方向、许可或连接关系","use":"造句、改写、基础语法替换，例如 \"very\" / \"tomorrow\" 的替换练习"},{"w":"yesterday","def":"yesterday: 可帮助扩展句型的基础词","vs":"与 tomorrow 相比，比主词更偏向另一个动作阶段或语气","use":"短句练习、问答转换，例如 \"yesterday\" / \"tomorrow\" 的替换练习"},{"w":"north","def":"north: 同一组 Basic English 操作词","vs":"与 tomorrow 相比，保留基础含义，但句中功能不同","use":"动词、介词、连词的搭配训练，例如 \"north\" / \"tomorrow\" 的替换练习"}]'),
