  ('north', 'op', 95, 'OP', '北；北方', 'the direction opposite south', 'The ship moved north in the morning.', '早上船向北移动。', '[{"w":"yesterday","def":"yesterday: 相关的动作或关系词","vs":"与 north 相比，用于和主词比较动作方向、许可或连接关系","use":"造句、改写、基础语法替换，例如 \"yesterday\" / \"north\" 的替换练习"},{"w":"south","def":"south: 可帮助扩展句型的基础词","vs":"与 north 相比，比主词更偏向另一个动作阶段或语气","use":"短句练习、问答转换，例如 \"south\" / \"north\" 的替换练习"},{"w":"east","def":"east: 同一组 Basic English 操作词","vs":"与 north 相比，保留基础含义，但句中功能不同","use":"动词、介词、连词的搭配训练，例如 \"east\" / \"north\" 的替换练习"}]');
